        Preconditions.checkState(childCount == 0);
        add("null");
        break;

      case Token.THIS:
        Preconditions.checkState(childCount == 0);
        add("this");
        break;

      case Token.FALSE:
        Preconditions.checkState(childCount == 0);
        add("false");
        break;

      case Token.TRUE:
